Move `useConditionalHook` outside the conditional:

```jsx
// ❌ Wrong
function Component({ show }) {
if (show) {
const [state, setState] = useState(0); // Violation!
}
}

// ✅ Correct
function Component({ show }) {
const [state, setState] = useState(0);
if (!show) return null;
// Use state here...
}
```

Extract loop body to a separate component:

```jsx
// ❌ Wrong
items.map(item => {
const [value, setValue] = useHook1(item.initial); // Violation!
return <Item value={value} />;
});

// ✅ Correct: Create a component for each item
function ItemWrapper({ item }) {
const [value, setValue] = useHook1(item.initial);
return <Item value={value} />;
}

items.map(item => <ItemWrapper key={item.id} item={item} />);
```

