Install and use helmet:
```bash
npm install helmet
```
```javascript
const helmet = require('helmet');
app.use(helmet());

// Or with custom config:
app.use(helmet({
contentSecurityPolicy: {
directives: {
defaultSrc: ["'self'"],
scriptSrc: ["'self'", "trusted-cdn.com"],
},
},
}));
```

